// Master planner for the Orchestrator. Builds one item per (persona, scenario)
// job, identical to the shape the old B/C planners produced. Each item will
// be sent to ONE Worker execution. The Worker then does Phase B+C+D for it.
//
// Respects exactly the same Config flags as before:
//   TIKTOK_ID         - target one or many accounts (comma-separated handles)
//   ONE_PER_PERSONA   - true: every persona / false: only personas with no video
//   MAX_VIDEOS_PER_RUN - scenarios per persona this run
const cfg = $('Config1').first().json;
const H = { apikey: cfg.SUPABASE_SECRET };

// Same scenario library as before
const SCENARIOS = [{"id": "gym_post_workout_mirror_01", "category": "gym", "archetype": "held_with_phone", "difficulty": "hard", "scene": "Modern commercial gym with a large floor-to-ceiling mirror wall; treadmills and cable machines softly out of focus behind the subject; large windows letting in late-afternoon golden-hour light; polished concrete floor.", "outfit": {"style_brief": "Matte black athletic set, minimal warm-metal jewellery, no-makeup freshness, post-workout polish.", "female": "Matte black ribbed seamless sports bra with thin straps, matching high-waist seamless black leggings, low black ankle socks, no shoes. Hair styled in a slick high ponytail with a few face-framing pieces left loose. Small gold huggie hoops, a touch of lip gloss, otherwise bare glowing skin.", "male": "Matte black fitted sweat-wicking training tank, matching black mid-thigh training shorts with a compression liner, low black ankle socks, no shoes. Hair styled neatly and pushed back off the face, lightly damp. A simple thin chain, clean groomed look."}, "pose": "Standing facing the mirror at a slight three-quarter angle, weight on one hip, the opposite foot slightly forward, posture relaxed and confident, a soft smile.", "hand_assignment": {"phone_hand": "left", "product_hand": "right", "free_hand_action": "the left hand holds the phone at face level, capturing the mirror reflection"}, "grip_or_placement": "Right hand at upper-chest level: thumb on the front face of the box near the top edge, index and middle fingers on the back of the box, ring and pinky tucked under, box angled forty-five degrees toward the mirror so the front face is clearly visible in the reflection.", "lighting": "Mixed gym lighting - cool overhead fluorescents combined with warm window backlight from late-afternoon sun behind the subject. Subtle rim light on shoulders and hair, neutral light on the box with a warm window-side rim.", "mood": "post-workout earned, lightly winded, composed", "palette": "bone white, concrete grey, warm window glow, charcoal black", "framing": "medium full (mid-thigh up)", "camera_height": "chest level"}, {"id": "gym_treadmill_water_break_02", "category": "gym", "archetype": "held_product_low", "difficulty": "medium", "scene": "Quiet corner of a premium gym; a single treadmill stationary in the background; soft natural daylight from a side window; polished wood floor area; a folded white gym towel draped over the treadmill handlebar.", "outfit": {"style_brief": "Sage-green athleisure, soft and tonal, a relaxed mid-workout pause, minimal gold accent.", "female": "Sage green long-sleeve cropped athletic pullover with thumbholes, matching sage green high-waist leggings, white minimalist running sneakers, a thin gold chain barely visible at the collarbone. Hair styled in a low loose ponytail.", "male": "Sage green long-sleeve fitted training top with thumbholes, matching sage green training joggers with a tapered leg, white minimalist running sneakers. Hair styled neat and natural. No jewellery, clean and understated."}, "pose": "Standing beside the treadmill, body angled three-quarters toward the camera, one hand resting on the treadmill handlebar, weight on one leg.", "hand_assignment": {"phone_hand": null, "product_hand": "right", "free_hand_action": "the left hand rests lightly on the treadmill handlebar"}, "grip_or_placement": "Right hand at hip level, palm slightly upward, the box held in a relaxed pinch grip - thumb on the top edge, four fingers underneath the bottom face, held flat horizontally with the front face angled slightly toward the camera.", "lighting": "Soft natural daylight from a side window, cool with a subtle warm undertone, neutral wash on the box surface.", "mood": "composed mid-workout pause", "palette": "sage green, polished wood warm tone, soft daylight white", "framing": "three-quarter (knee up)", "camera_height": "chest level"}, {"id": "gym_weights_area_cooldown_03", "category": "gym", "archetype": "placed_on_surface", "difficulty": "medium", "scene": "Weights area of a premium gym; a dumbbell rack in soft focus behind; black rubber flooring; a lifting bench in the foreground; industrial pendant lighting overhead; a dark exposed-brick wall on the right.", "outfit": {"style_brief": "Deep burgundy athletic set, warm industrial gym, post-set recovery.", "female": "Deep burgundy cropped tank top, matching burgundy bike shorts with a double-band waistband, cropped white socks, white minimalist trainers. Hair styled in a messy bun on top of the head with a few loose pieces. Small silver studs.", "male": "Deep burgundy fitted athletic tank, matching burgundy training shorts with a double-band waistband, cropped white socks, white minimalist trainers. Hair styled short and slightly damp from the workout. No jewellery."}, "pose": "Sitting on the lifting bench, knees apart, leaning slightly forward with forearms resting on the thighs, looking off-camera to the side as if catching breath after a set.", "hand_assignment": {"phone_hand": null, "product_hand": null, "free_hand_action": "both forearms rest forward on the thighs"}, "grip_or_placement": "The product box sits on the lifting bench beside the subject's right thigh, front face angled toward the camera, a stainless steel water bottle next to it and a small folded grey gym towel beside both. The product is the foreground hero of the surface arrangement.", "lighting": "Warm overhead industrial pendant light slightly behind the subject, a soft warm rim on shoulders and hair, cooler ambient fill from the gym ceiling, a warm glow on the box's front face.", "mood": "post-set quiet recovery", "palette": "deep burgundy, charcoal black, warm pendant amber, polished concrete grey", "framing": "three-quarter (waist up, bench surface visible to the right)", "camera_height": "slightly below eye line, looking up"}, {"id": "gym_locker_room_finish_04", "category": "gym", "archetype": "held_product_high", "difficulty": "medium", "scene": "Premium gym locker room; light wood lockers behind; a long wooden bench in the foreground with a folded white gym towel and a small leather duffel bag on it; soft warm sconce lighting on the wall.", "outfit": {"style_brief": "Oversized heather-grey loungewear layered over an athletic base, end-of-workout calm.", "female": "Heather grey oversized cropped sweatshirt over a black sports bra with the strap visible at the neckline, matching heather grey wide-leg sweatpants pooling at the ankles, white slip-on sneakers. Damp hair worn down with the front pieces twisted back loosely. A single thin gold chain.", "male": "Heather grey oversized crewneck sweatshirt over a black athletic base layer with the crew collar visible, matching heather grey wide-leg sweatpants pooling at the ankles, white slip-on sneakers. Damp hair pushed back off the face. No jewellery."}, "pose": "Standing beside the bench, body angled three-quarters toward the camera, one foot slightly raised on the bench, looking down at the box in hand with a soft satisfied half-smile.", "hand_assignment": {"phone_hand": null, "product_hand": "right", "free_hand_action": "the left hand tucks damp hair behind the ear"}, "grip_or_placement": "Right hand at chest level: thumb on the front face, index and middle fingers wrapping the right side, ring and pinky tucked under the bottom edge, box held vertically (long side vertical) with the front face turned to the camera.", "lighting": "Warm sconce lighting from behind, soft overhead locker-room light, a gentle golden cast across the wood lockers, warm tones on the box surface.", "mood": "post-shower satisfied, end-of-workout calm", "palette": "warm wood, heather grey, cream towel, soft amber", "framing": "three-quarter (waist up)", "camera_height": "chest level"}, {"id": "office_desk_midday_05", "category": "office", "archetype": "placed_on_surface", "difficulty": "medium", "scene": "Sleek modern home office; a light walnut desk against a soft cream wall; an open silver laptop turned slightly away from camera; a ceramic mug of black coffee on a marble coaster; a stack of two design books with a small snake plant in a terracotta pot; a tortoiseshell pen across an open leather notebook; a large window to the right with sheer linen curtains diffusing midday light.", "outfit": {"style_brief": "Polished smart-casual in cream and navy, premium work-from-home register, considered and quiet.", "female": "Navy blue silk camisole under a soft cream cashmere V-neck cardigan buttoned only at the top button, matching cream wide-leg tailored trousers with a slight crop hem, woven flat leather slides. Hair styled in a low half-up twist with a small tortoiseshell claw clip, the rest in soft waves. Small gold studs, a thin gold pendant, subtle polished daytime makeup.", "male": "A navy fine-knit short-sleeve polo under a soft cream lightweight cashmere cardigan worn open, matching cream tailored trousers with a slight crop hem, woven leather loafers. Hair styled neatly. A simple watch with a tan leather strap, clean groomed look."}, "pose": "Seated at the desk in three-quarter angle to the camera, body turned slightly toward the laptop, one hand resting on the open notebook, the other pulled back from the keyboard mid-thought, looking softly at the product on the desk with a small contemplative smile.", "hand_assignment": {"phone_hand": null, "product_hand": null, "free_hand_action": "one hand rests on the open notebook, the other is pulled back from the keyboard mid-thought"}, "grip_or_placement": "The product box sits on the desk between the coffee mug and the open notebook, front face directly toward the camera, long side horizontal, positioned slightly forward of the laptop at the visual centre of the desk so it reads as the hero of the workspace.", "lighting": "Bright but soft midday daylight filtered through sheer linen curtains on the right, a neutral diffuse wash across the face and the walnut desk, a very gentle warm undertone on the box's front face, no harsh shadows.", "mood": "mid-workday wellness moment, polished focus", "palette": "cream cashmere, navy, warm walnut, ivory ceramic, soft sage green", "framing": "medium close-up (chest up, desk surface visible at lower frame)", "camera_height": "slightly above eye line, looking gently down at the desk"}, {"id": "pilates_reformer_mirror_06", "category": "pilates", "archetype": "held_with_phone", "difficulty": "hard", "scene": "Premium pilates studio; a sage-green reformer machine behind the subject; a tall floor-to-ceiling mirror the subject faces; warm marble floor; an exposed brick side wall; a tall window on the left letting in late-afternoon sun.", "outfit": {"style_brief": "Tonal cream activewear, soft and minimal, post-class polish, barefoot studio convention.", "female": "Cream ribbed seamless cropped tank with a built-in shelf bra, matching cream high-waist seamless leggings, bare feet. Small gold huggie earrings, a thin gold pendant. Hair styled down in soft natural waves with a centre part, clean neutral nails.", "male": "A cream fitted seamless training tee, matching cream tapered training tights, bare feet. Hair styled neat with a natural part. No jewellery, clean and minimal."}, "pose": "Standing facing the mirror, weight on one leg, the opposite knee slightly bent, posture upright with a soft confident smile.", "hand_assignment": {"phone_hand": "right", "product_hand": "left", "free_hand_action": "the right hand holds the phone at face level, capturing the mirror reflection"}, "grip_or_placement": "Left hand at chest level: thumb pressed flat on the front face, four fingers wrapping the back edge, box held perpendicular to the body so the front face points directly at the mirror.", "lighting": "Soft warm natural daylight through a tall window on the left, late afternoon, warm bone tones across the marble floor, a gentle warm rim on the left side and a warm glow on the box's front face.", "mood": "post-class composed, polished", "palette": "cream, beige, sage green, warm marble bone", "framing": "medium full (mid-thigh up)", "camera_height": "chest level"}, {"id": "yoga_home_practice_07", "category": "yoga", "archetype": "held_product_high", "difficulty": "hard", "scene": "Sunlit corner of a minimalist home; warm wood floor; a cork-textured yoga mat unrolled diagonally across the frame; a terracotta zafu meditation cushion at the upper end; a small Tibetan singing bowl with a wooden mallet beside it; a sprig of dried lavender on the floor; a large pothos plant in a woven basket against the wall.", "outfit": {"style_brief": "Dusty mauve seamless training set, meditative warmth, glowy fresh-practice skin.", "female": "Dusty mauve seamless ribbed cropped long-sleeve top with thumbholes, matching dusty mauve high-waist seamless leggings with a wide waistband, bare feet. Hair styled in a high half-up topknot with the lower half in soft waves. Small gold huggie hoops, a thin gold ring. Glowy skin with a touch of bronze on the eyelids.", "male": "A dusty mauve seamless ribbed long-sleeve training top with thumbholes, matching dusty mauve relaxed-fit training shorts, bare feet. Hair styled neatly back off the face. No jewellery, fresh natural skin."}, "pose": "Kneeling on the yoga mat in a seiza-style sitting position (legs folded under, sitting back on the heels), posture upright and aligned, shoulders relaxed, looking softly down at the product held in front at chest level with a serene calm half-smile.", "hand_assignment": {"phone_hand": null, "product_hand": "both", "free_hand_action": "both hands cradle the box together at chest level"}, "grip_or_placement": "Both hands cradle the box together at chest level, palms facing up and meeting at the centreline of the body, the box resting flat horizontally on the fingertips with thumbs gently pressing the front face on either side, four fingers of each hand cradling the back edge. Front face angled gently up toward the camera at a soft fifteen-degree tilt.", "lighting": "Soft warm early-evening golden-hour daylight from a tall window just out of frame on the left, a gentle directional warm wash across the left side of the body and the front face of the box, a deeper warm shadow on the right side, warm honeyed tones across the wood floor and cork mat.", "mood": "meditative intentional, end-of-practice reflection", "palette": "dusty mauve, warm wood, terracotta, soft sage green, warm golden light", "framing": "medium close-up (waist up, hands and product centred)", "camera_height": "chest level (matching the kneeling height), straight-on"}, {"id": "pilates_studio_entrance_08", "category": "pilates", "archetype": "held_product_high", "difficulty": "medium", "scene": "Entrance hallway of a premium pilates studio; warm wood floor; a sage-green wall on the right; a tall mirror on the left wall reflecting the studio interior; a small wooden bench against the right wall with a rolled cream towel and a straw tote bag; soft morning light through the front door at the far end.", "outfit": {"style_brief": "Pale buttery-yellow activewear, fresh arriving energy, light and clean.", "female": "Pale buttery yellow ribbed seamless tank top, matching pale yellow high-waist bike shorts, white slip-on canvas sneakers, a small gold cuff bracelet. Hair styled in a low loose bun at the nape. Subtle gold huggie earrings.", "male": "A pale buttery yellow ribbed seamless training tee, matching pale yellow mid-thigh training shorts, white slip-on canvas sneakers. Hair styled short and neat. No jewellery."}, "pose": "Walking toward the camera at a slight three-quarter angle, mid-stride, one foot just leaving the floor, looking slightly off-camera with a soft natural smile.", "hand_assignment": {"phone_hand": null, "product_hand": "right", "free_hand_action": "the left hand holds the strap of a small straw tote bag at the side"}, "grip_or_placement": "Right hand at chest level held slightly forward of the body: thumb on the front face, four fingers wrapping the back edge, box held at a relaxed angle three-quarters toward the camera.", "lighting": "Soft warm morning daylight from the open front door at the end of the hallway, a golden cast on the wood floor, warm rim light on the right side.", "mood": "arriving fresh, calm energy", "palette": "pale buttery yellow, warm wood, sage green, cream", "framing": "full body (head to mid-shin)", "camera_height": "slightly below eye line, looking up gently"}, {"id": "pilates_mat_morning_handheld_09", "category": "pilates", "archetype": "held_product_low", "difficulty": "medium", "scene": "Sunlit pilates studio; a cream-colored mat on the warm wood floor; a sage-green reformer in the background out of focus; a tall window on the right flooding morning light into the room.", "outfit": {"style_brief": "Dusty pink seamless set, soft morning calm, barefoot, glowy fresh skin.", "female": "Soft dusty pink seamless sports bra with crossback straps, matching dusty pink high-waist leggings, a thin gold anklet, bare feet. Hair styled down in soft beach waves with a centre part, glowy skin, no makeup.", "male": "A soft dusty pink seamless fitted training tee, matching dusty pink relaxed training shorts, bare feet. Hair styled neat with a natural part. No jewellery, fresh natural skin."}, "pose": "Sitting cross-legged on the mat, posture upright, hands resting in the lap, looking down at the box with a soft contemplative smile.", "hand_assignment": {"phone_hand": null, "product_hand": "both", "free_hand_action": "both hands hold the box together in the lap"}, "grip_or_placement": "Both hands cradle the box in the lap, palms facing up and slightly together, the box resting on the fingertips with the front face angled toward the camera at a slight upward tilt, thumbs resting on either side of the front face.", "lighting": "Bright soft morning daylight from a tall window on the right, warm bone tones across the wood floor and mat, a gentle warm wash on the right side and on the box surface.", "mood": "morning intention setting, peaceful", "palette": "dusty pink, warm wood, cream mat, sage green", "framing": "three-quarter (head to crossed knees)", "camera_height": "slightly below eye line, looking up"}, {"id": "pilates_studio_post_class_mirror_10", "category": "pilates", "archetype": "held_product_high", "difficulty": "hard", "scene": "Premium pilates studio viewed from a fresh angle; warm marble floor; a sage-green reformer behind; an exposed brick wall on the right; the subject standing in front of a floor-to-ceiling mirror with the reformer reflected behind.", "outfit": {"style_brief": "Slate-grey seamless long-sleeve set, cool-toned and poised, silver accents.", "female": "Slate grey seamless ribbed cropped long-sleeve top with thumbholes, matching slate grey high-waist seamless leggings, a thin silver chain necklace, small silver hoops, bare feet. Hair styled in a low slick ponytail with a small clip. Subtle natural makeup.", "male": "A slate grey seamless ribbed long-sleeve training top with thumbholes, matching slate grey tapered training tights, bare feet. Hair styled neatly slicked back. A simple thin silver chain."}, "pose": "Standing in three-quarter angle to the mirror, weight on one leg, the free hand on the hip, posture confident and relaxed.", "hand_assignment": {"phone_hand": null, "product_hand": "right", "free_hand_action": "the left hand rests lightly on the hip"}, "grip_or_placement": "Right hand at upper-chest level, box held in a clear pinch grip - thumb on the front face near the bottom edge, index and middle fingers on the back, ring and pinky tucked under, box angled slightly toward the camera for direct camera engagement (not toward the mirror).", "lighting": "Soft warm late-afternoon daylight through a tall window on the left, warm bone tones across the marble floor, a gentle warm glow on the box surface, subtle rim light on the left shoulder.", "mood": "post-class polished, poised", "palette": "slate grey, warm marble bone, sage green, soft amber", "framing": "medium close-up (chest up)", "camera_height": "chest level"}, {"id": "bedroom_bed_handheld_close_11", "category": "bedroom", "archetype": "held_product_high", "difficulty": "hard", "scene": "Bedroom morning; soft white bedding with a leopard-print pillowcase visible behind the head; a light wood headboard partially visible; a sheer white curtain on a window to the right letting in soft golden morning light.", "outfit": {"style_brief": "Relaxed morning sleepwear in soft ivory, just-woke warmth, bare glowy skin.", "female": "A pale ivory satin slip nightgown with thin spaghetti straps, slightly crumpled from sleep, the top of the slip visible at the neckline. Hair styled tousled from sleep in soft waves spread on the pillow. Bare face, glowy skin, no earrings.", "male": "A soft ivory cotton short-sleeve sleep tee, slightly crumpled from sleep, the crew neckline visible. Hair styled tousled from sleep. Bare face, fresh skin, no accessories."}, "pose": "Lying on the back on the pillow, photographed from above-front so the face and upper chest are visible, a soft sleepy half-smile at the camera.", "hand_assignment": {"phone_hand": null, "product_hand": "right", "free_hand_action": "the left hand rests near the chin, fingers lightly curled"}, "grip_or_placement": "Right hand raised in front of the face holding the box vertically, thumb on one side and four fingers wrapped around the opposite side, box positioned about twenty centimetres from the face with the front face angled directly at the camera.", "lighting": "Soft warm morning daylight from the window on the right, a diffuse golden wash across the face and pillow, no harsh shadows, a gentle warm glow on the box surface.", "mood": "playful first-thing-morning, sleepy soft smile", "palette": "ivory satin, leopard tan, warm white, skin warmth", "framing": "close-up (head and upper chest, box dominant in frame)", "camera_height": "directly above the face, slight tilt"}, {"id": "bedroom_vanity_getting_ready_12", "category": "bedroom", "archetype": "placed_on_surface", "difficulty": "medium", "scene": "Bedroom vanity area; a round arched mirror on a warm walnut vanity; arranged skincare bottles and a small ceramic dish on a gold tray; a linen-shaded lamp glowing warmly in the corner; soft early-morning light from a window out of frame.", "outfit": {"style_brief": "Soft blush morning robe over a light base layer, gentle skincare-moment calm.", "female": "A pale blush pink linen robe loosely tied at the waist with a slim ribbon sash, the V-neckline open showing a thin white camisole strap underneath. Hair clipped half-up in a claw clip, the lower half in soft waves. Bare face mid-skincare application.", "male": "A pale blush-grey waffle short robe loosely tied at the waist over a plain white crew tee, the neckline open. Hair styled lightly tousled, freshly woken. Bare face mid-skincare application."}, "pose": "Sitting on a small upholstered vanity stool, three-quarter angle to the camera, one hand at the cheek mid-skincare gesture, looking toward the reflection in the mirror.", "hand_assignment": {"phone_hand": null, "product_hand": null, "free_hand_action": "one hand is lifted to the cheek mid-skincare application"}, "grip_or_placement": "The product box sits on the vanity surface to the subject's right, positioned between a ceramic skincare bottle and an open glass jar of cotton pads, front face angled three-quarters toward the camera as the visual anchor of the vanity arrangement.", "lighting": "Warm bedside lamp from the corner combined with soft morning daylight from a window out of frame on the left, warm honeyed tones across the walnut vanity, a gentle warm glow on the box surface.", "mood": "slow morning skincare moment, soft and unhurried", "palette": "warm walnut, blush pink, soft amber lamp glow, ivory ceramics", "framing": "three-quarter (head to waist, vanity surface visible)", "camera_height": "chest level"}, {"id": "bedroom_robe_with_product_13", "category": "bedroom", "archetype": "held_product_low", "difficulty": "medium", "scene": "Bedroom doorway leading to a softly-lit bathroom in the background; hardwood floor; a low cream bench in front of the doorway with a folded white towel and a ceramic mug; soft morning light from windows throughout.", "outfit": {"style_brief": "Long cream waffle-knit robe, soft morning-routine ease.", "female": "A long cream waffle-knit robe tied loosely at the waist, falling to mid-shin, the V-neckline open with a thin white camisole strap underneath. Hair styled down in loose tousled morning waves. Small gold studs, bare face, glowy skin.", "male": "A long cream waffle-knit robe tied loosely at the waist over a plain white crew tee and soft grey lounge shorts. Hair styled lightly tousled. No accessories, fresh skin."}, "pose": "Standing in the doorway angled slightly to one side, weight on one leg, looking down at the box in hand with a soft contemplative smile.", "hand_assignment": {"phone_hand": null, "product_hand": "left", "free_hand_action": "the right hand gently holds the edge of the doorframe"}, "grip_or_placement": "Left hand at hip level, palm facing up, the box resting flat on the open palm with the thumb gently on top to steady it, front face toward the camera - a relaxed casual hold, not a presentation grip.", "lighting": "Soft warm morning daylight from windows on either side, a balanced diffuse wash, a gentle warm glow on the cream robe and the box.", "mood": "morning routine pause, considering the start of the day", "palette": "cream waffle, warm wood, soft white, blush undertones", "framing": "full body (head to mid-shin)", "camera_height": "chest level"}, {"id": "bedroom_journaling_evening_14", "category": "bedroom", "archetype": "placed_on_surface", "difficulty": "medium", "scene": "Bedroom corner writing nook at twilight; a vintage caramel-leather armchair angled slightly toward the camera; a small warm-wood side table with a brass desk lam