 the nightstand"}, {"id": "garden_terrace_morning_30", "category": "outdoor", "archetype": "held_product_high", "difficulty": "medium", "scene": "A private home terrace at morning golden hour; terracotta tile flooring with a subtle natural patina; low square planters along the edge holding small ornamental olive trees and trailing rosemary; a small round mosaic-topped table with a ceramic mug of coffee with visible steam and a small saucer with a single fresh fig; beyond the terrace railing a softly blurred warm Mediterranean cityscape with terracotta rooftops and soft hills.", "outfit": {"style_brief": "Cream linen warm-weather outfit, serene Mediterranean morning.", "female": "A cream linen sleeveless midi sundress with a deep V-neckline, a thin self-fabric belt cinched at the natural waist, a relaxed A-line skirt to mid-calf. Woven natural-fiber flat espadrille sandals just visible. Layered thin gold necklaces of varying lengths, a thin gold cuff bracelet, small gold huggie hoops. Hair styled down in soft natural beach waves with a slight side part, a touch of bronzer and tinted lip balm for a glowy bronzed look.", "male": "A cream linen short-sleeve camp-collar shirt worn relaxed with two top buttons open, paired with cream linen drawstring trousers, woven natural-fiber flat sandals just visible. Hair styled short and neat. A thin gold chain, otherwise minimal, glowy bronzed skin."}, "pose": "Standing on the terrace at a slight three-quarter angle to the camera, weight on one leg with the opposite foot slightly forward, one hand resting lightly on the low planter wall, body angled toward the soft view beyond, looking softly toward the box held at chest level with a serene content smile.", "hand_assignment": {"phone_hand": null, "product_hand": "right", "free_hand_action": "the left hand rests lightly on the low planter wall"}, "grip_or_placement": "Right hand at upper-chest level held slightly forward of the body: thumb pressed flat on the front face near the top edge, index and middle fingers on the back edge, ring and pinky tucked under the bottom edge, box held vertically (long side vertical) with the front face angled gently toward the camera, catching the warm morning sun directly.", "lighting": "Strong warm morning golden-hour sunlight from a low angle on one side, a directional warm wash across that side of the body and across the front face of the box creating a warm golden rim, deep amber tones across the terracotta tiles, a soft cool sky-blue ambient fill from above.", "mood": "morning golden-hour terrace ritual, serene Mediterranean energy", "palette": "cream linen, terracotta tile, olive green, warm golden morning, soft sky", "framing": "medium full (mid-thigh up, terrace surface and planters visible)", "camera_height": "chest level, slight three-quarter angle"}];
const scById = {}; for (const s of SCENARIOS) scById[s.id] = s;
const SCEN_ORDER = SCENARIOS.slice().sort((a, b) =>
  String(a.id).localeCompare(String(b.id), undefined, { numeric: true }));

// Load personas (with their tiktok_accounts joined for demographics)
const personas = await this.helpers.httpRequest({ method:'GET',
  url: cfg.SUPABASE_URL + '/rest/v1/personas?select=*,tiktok_accounts(*)',
  headers: H, json: true });
if (!personas || personas.length === 0) return [];

// What (persona, scenario) pairs already have a finished video?
const videosJoined = await this.helpers.httpRequest({ method:'GET',
  url: cfg.SUPABASE_URL + '/rest/v1/videos?select=output_id,scenario_id,outputs(persona_id,scenario_id)',
  headers: H, json: true });
const donePairs = new Set();
const personasWithVideo = new Set();
for (const v of (videosJoined || [])) {
  const pid = v.outputs ? v.outputs.persona_id : null;
  const sid = (v.outputs && v.outputs.scenario_id) || v.scenario_id;
  if (pid != null && sid != null) { donePairs.add(pid+'::'+sid); personasWithVideo.add(pid); }
}

// Select personas per the three flags - same logic as before
const rawTikId = cfg.TIKTOK_ID;
const tikList = (rawTikId && rawTikId !== false && String(rawTikId).trim() !== '')
  ? String(rawTikId).split(',').map(s => s.trim()).filter(Boolean) : [];
let selected;
if (tikList.length > 0) {
  const wanted = new Set(tikList.map(s => s.toLowerCase()));
  selected = personas.filter(p => {
    const tid = p.tiktok_accounts && p.tiktok_accounts.tiktok_id;
    return tid && wanted.has(String(tid).toLowerCase());
  });
} else if (cfg.ONE_PER_PERSONA === true) {
  selected = personas;
} else {
  selected = personas.filter(p => !personasWithVideo.has(p.id));
}

// Per selected persona, take next N undone scenarios
const N = Math.max(1, Number(cfg.MAX_VIDEOS_PER_RUN) || 1);
const jobs = [];
for (const p of selected) {
  let taken = 0;
  for (const sc of SCEN_ORDER) {
    if (taken >= N) break;
    if (donePairs.has(p.id+'::'+sc.id)) continue;
    jobs.push({ json: {
      persona_id: p.id,
      persona_drive_file_id: p.drive_file_id,
      gender: (p.tiktok_accounts && p.tiktok_accounts.gender) ? String(p.tiktok_accounts.gender).toLowerCase() : 'female',
      country: p.tiktok_accounts ? p.tiktok_accounts.country : '',
      age: p.tiktok_accounts ? p.tiktok_accounts.age : null,
      scenario_id: sc.id,
      scenario: sc
    } });
    taken++;
  }
}
return jobs;

