return [{ json: CONFIG }];

// Emits ALL tiktok_accounts (keeps the workflow flowing), tagged needs_persona.
// tiktok_accounts is the persona INPUT table (replaces the old signups table).
const cfg = $('Config1').first().json;
const H = { apikey: cfg.SUPABASE_SECRET };
const accounts = await this.helpers.httpRequest({
  method:'GET', url: cfg.SUPABASE_URL + '/rest/v1/tiktok_accounts?select=*', headers:H, json:true });
const personas = await this.helpers.httpRequest({
  method:'GET', url: cfg.SUPABASE_URL + '/rest/v1/personas?select=*', headers:H, json:true });
if (!accounts || accounts.length === 0) {
  throw new Error('The tiktok_accounts table is empty. Insert account rows in Supabase first.');
}
const have = new Set((personas || []).map(p => p.tiktok_account_id));
return accounts.map((a, i) => ({ json: { ...a, needs_persona: !have.has(a.id) }, pairedItem: { item: i } }));

// Builds the Anthropic request that writes each persona portrait prompt.
const cfg = $('Config1').first().json;
const PERSONA_SYSTEM = `You are a senior photographic casting director and prompt engineer. You write ONE text-to-image prompt for Google's Nano Banana Pro (Gemini 3 Pro Image) model.

YOUR JOB: turn a short demographic brief into ONE richly detailed prompt that produces a photorealistic, casting-quality PORTRAIT of a real-looking person. This portrait becomes a locked identity reference reused across many later images, so it must be clean, neutral, evenly lit and unambiguous.

HARD RULES:
- Output ONLY the prompt text. No preamble, no quotes, no labels, no commentary.
- Describe a REAL, natural, believable human whose appearance is demographically representative of the given country and age. Aim for an ordinary, authentic, naturally attractive person you would genuinely cast for a lifestyle ad - never a caricature or stereotype.
- Nano Banana Pro has a very large context window and rewards specificity. Write a long, dense, concrete paragraph.
- Use PHOTOGRAPHIC language: full-frame camera, 85mm portrait lens, aperture near f/2.8, soft natural window light, gentle shallow depth of field, a plain seamless neutral-grey or soft-neutral studio background.
- Demand REAL SKIN: visible pores, fine natural texture, subtle natural asymmetry, faint age-appropriate lines, natural skin sheen - explicitly natural and lifelike, never airbrushed, waxy, plastic or over-smoothed.
- Framing: a head-and-shoulders to mid-torso portrait, the person centred, facing the camera, with a relaxed, friendly-neutral expression and a soft natural look directly into the lens.
- Wardrobe: simple, plain, unbranded, solid-colour modern casual clothing. The outfit is deliberately minimal because it will be changed in later steps.
- The frame contains only the person against the background - a clean portrait.
- Use ONLY positive description. Nano Banana does not reliably honour negations.
- Lighting must be even and flattering so the face reads clearly as a reusable identity reference.

Write the prompt as flowing photographic prose.`;
return $input.all().map((it, i) => {
  const a = it.json;
  const userMsg = 'Country / ethnicity context: ' + a.country
    + '
Gender: ' + a.gender + '
Approximate age: ' + a.age
    + '

Write the portrait prompt for this person.';
  return { json: {
    account: a,
    _url: 'https://api.anthropic.com/v1/messages',
    _headers: { 'x-api-key': cfg.ANTHROPIC_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    _body: { model: cfg.ANTHROPIC_MODEL, max_tokens: 1500, system: PERSONA_SYSTEM, messages: [{ role: 'user', content: userMsg }] }
  }, pairedItem: { item: i } };
});

// Parses the persona prompt and builds the FAL text-to-image request.
const cfg = $('Config1').first().json;
const prev = $('A: Build Persona Prompt Req1').all();
return $input.all().map((it, i) => {
  const anth = it.json;
  const carried = prev[i].json;
  const prompt = (anth.content || []).filter(b => b.type === 'text').map(b => b.text).join('').trim();
  return { json: {
    account: carried.account, prompt,
    _url: 'https://fal.run/' + cfg.FAL_T2I_MODEL,
    _headers: { 'Authorization': 'Key ' + cfg.FAL_KEY, 'content-type': 'application/json' },
    _body: { prompt, num_images: 1, output_format: 'png', aspect_ratio: cfg.PERSONA_ASPECT }
  }, pairedItem: { item: i } };
});

// Downloads the generated persona image and attaches it as binary.
const prev = $('A: Build FAL t2i Req1').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const fal = items[i].json;
  const carried = prev[i].json;
  const url = fal && fal.images && fal.images[0] && fal.images[0].url;
  if (!url) continue;   // FAL failed for this one - skipped, retried next run
  const raw = await this.helpers.httpRequest({ method: 'GET', url, encoding: 'arraybuffer', timeout: 120000 });
  const buf = Buffer.from(raw);
  const filename = 'persona_acct' + carried.account.id + '.png';
  out.push({
    json: { tiktok_account_id: carried.account.id, persona_filename: filename, prompt_used: carried.prompt },
    binary: { data: await this.helpers.prepareBinaryData(buf, filename, 'image/png') }
  });
}
return out;

// Inserts each persona into Supabase (upsert on tiktok_account_id).
const cfg = $('Config1').first().json;
const H = { apikey: cfg.SUPABASE_SECRET, 'content-type': 'application/json',
            Prefer: 'return=representation,resolution=merge-duplicates' };
const gens = $('A: Finalize Persona1').all().map(i => i.json);
const byName = {};
for (const g of gens) byName[g.persona_filename] = g;
const out = [];
for (const item of $input.all()) {
  const f = item.json;
  const g = byName[f.name] || {};
  const row = {
    tiktok_account_id: g.tiktok_account_id, drive_file_id: f.id,
    drive_url: f.webViewLink || ('https://drive.google.com/file/d/' + f.id + '/view'),
    prompt_used: g.prompt_used || '', status: 'done'
  };
  const res = await this.helpers.httpRequest({
    method: 'POST', url: cfg.SUPABASE_URL + '/rest/v1/personas?on_conflict=tiktok_account_id',
    headers: H, body: row, json: true });
  out.push({ json: { recorded_persona: Array.isArray(res) ? res[0] : res } });
}
return out;
